    protected MaandTotaal1 maakMaandTotaal1PO(
            Opdracht opdracht, RekenHoofdArtikelKey key, RekenTijd rekenTijd, boolean vorigKwartaal,
            LocalDateInterval maandTotaalPeriode, Integer sNummer) {
        Integer kostenplaats = key.getKostenplaats();
        if (kostenplaats == null) {
            kostenplaats = 0;
        }
        MaandTotaal1 maandTotaal1 = new MaandTotaal1PO();

        initialiseerNonNullVelden(maandTotaal1);

        maandTotaal1.setRnummer(key.getRnummer());
        maandTotaal1.setSnummer(sNummer);
        maandTotaal1.setAangifteId(key.getRszppoAangifteId());
        maandTotaal1.setDmfaWgAangifteId(key.getDmfapplAangifteId());
        maandTotaal1.setKostenplaats(kostenplaats);
        maandTotaal1.setFysischeKostenplaats(kostenplaats);

        maandTotaal1.setWerkgeverNummer(opdracht.getWerkgever().getWerkgeverNr());
        maandTotaal1.setPersoon(opdracht.getPersoon());
        maandTotaal1.setOpdrachtNummer(opdracht.getOpdrachtnr());
        LocalDate beginDatum = rekenTijd.beginDatum;
        maandTotaal1.setBeginDatum(maandTotaalPeriode.getStart());
        maandTotaal1.setEindDatum(maandTotaalPeriode.getEnd());
        maandTotaal1.setRekenTijdstip(key.getRekenTijdstip());
        maandTotaal1.setRekenDatum(key.getRekenDatum());
        maandTotaal1.setBeslagDatum(key.getBeslagDatum());

        maandTotaal1.setCategorie(key.getCategorie().getCode());
        maandTotaal1.setWerkgeversCategorie(key.getWerkgeversCategorie().getCode());
        maandTotaal1.setWerknemersKengetal(key.getWerknemersKengetal().getCode());
        maandTotaal1.setPensioenStelsel(key.getPensioenStelsel().getCode());

        maandTotaal1.setFiscaalJaar(key.getFiscaalJaar());
        maandTotaal1.setBoekJaar(key.getBoekJaar());

        maandTotaal1.setHoedanigheid(key.getHoedanigheid().getCode());

        LocalDate datumJaarKwartaal = bepaalDatumJaarKwartaal(rekenTijd, vorigKwartaal, beginDatum);
        maandTotaal1.setJaarKwartaal(datumJaarKwartaal.getYear() * 10 + TimeTools.bepaalKwartaal(datumJaarKwartaal));
        maandTotaal1.setRekenModus(key.getRekenModus().getCode());
        maandTotaal1.setRekengroep(key.getRekenGroep().getCode());
        AardMaandtotaal aardMaandtotaal = bepaalAardMaandTotaal(opdracht, rekenTijd);
        maandTotaal1.setAard(aardMaandtotaal);
        maandTotaal1.setManueleTussenkomst(0);

        maandTotaal1.setFysischArtikel(key.getArtikel());
        maandTotaal1.setBoekArtikel(key.getArtikel());

        MaandTotaal2 maandTotaal2 = new MaandTotaal2PO();
        maandTotaal1.setMaandTotaal2(maandTotaal2);

        MaandTotaal3 maandTotaal3 = new MaandTotaal3PO();
        maandTotaal1.setMaandTotaal3(maandTotaal3);

        ReflectionUtil.initialiseerMoneyVelden(maandTotaal1);
        ReflectionUtil.initialiseerMoneyVelden(maandTotaal2);
        ReflectionUtil.initialiseerMoneyVelden(maandTotaal3);

        return maandTotaal1;
    }

    private static AardMaandtotaal bepaalAardMaandTotaal(Opdracht opdracht, RekenTijd rekenTijd) {
        AardMaandtotaal aardMaandtotaal;
        if (rekenTijd.isApo) {
            aardMaandtotaal = AardMaandtotaal.AST_PRE_OMSCH;
        } else if (RekenTools.isOpdrachtMetKwartaalMaandtotalen(opdracht.getHoedanigheid())) {
            aardMaandtotaal = AardMaandtotaal.KWARTAAL;
        } else {
            aardMaandtotaal = AardMaandtotaal.MAAND;
        }
        return aardMaandtotaal;
    }

    private static LocalDate bepaalDatumJaarKwartaal(RekenTijd rekenTijd, boolean vorigKwartaal, LocalDate beginDatum) {
        LocalDate datumJaarKwartaal;
        if (vorigKwartaal) {
            datumJaarKwartaal = TimeTools.bepaalSelectieDatumVorigKwartaalDmfappl(rekenTijd);
        } else {
            datumJaarKwartaal = beginDatum;
        }
        return datumJaarKwartaal;
    }

    private static void initialiseerNonNullVelden(MaandTotaal1 maandTotaal1) {
        maandTotaal1.setOldArtikel("");
        maandTotaal1.setSnummer(0);
        maandTotaal1.setAangifteId(0);
        maandTotaal1.setDmfaWgAangifteId(0);
    }

    protected void vormInhoudingen(
            RekenHoofdArtikelKey rekenHoofdArtikelKey, Opdracht opdracht, ArtikelLoonElementManager manager,
            MaandTotaal1 maandTotaal1, ListMultimap<RekenElementenKey, Inhouding> opdrachtNrLooncodeToInhoudingen) {
        Collection<LoonElement> elementen =
                RekenElementBeheer.getRekenHoofdArtikelElementenKwartaal(rekenHoofdArtikelKey, manager, maandTotaal1.getAard());
        Set<Inhouding> inhoudingen = new HashSet<>();
        MoneyMap<RekenElementenKey> inhoudingBedragMap = new HashMoneyMap<>();
        for (LoonElement element : elementen) {
            AardKodeExtensie loonCode = element.getAardKodeExtensie();
            if (loonCode.getAard().equals(AardKodeExt.I_KODE_EXT.getCode()) && !isBijpassingNetto(loonCode)) {
                LocalDate beginDatum = maandTotaal1.getBeginDatum().dayOfMonth().withMinimumValue();
                LocalDate eindDatum = beginDatum.dayOfMonth().withMaximumValue();
                RekenElementenKey key = new RekenElementenKey(opdracht.getOpdrachtnr(), loonCode, 0, beginDatum, eindDatum);
                inhoudingBedragMap.addToMoney(key, bepaalBedragInhouding(element));
            }
        }
        Set<RekenElementenKey> sleutels = new HashSet<>();
        sleutels.addAll(opdrachtNrLooncodeToInhoudingen.keySet());
        sleutels.addAll(inhoudingBedragMap.keySet());
        for (RekenElementenKey key : sleutels) {
            List<Inhouding> bestaandeInhoudingen = opdrachtNrLooncodeToInhoudingen.get(key);
            Money bedrag = inhoudingBedragMap.getMoney(key);
            bedrag = MaandTotaalUtil.maakInhoudingVerschil(bedrag, bestaandeInhoudingen);

            if (bedrag.signum() != 0) {
                Inhouding inhouding = maakInhouding(key, bedrag);
                inhouding.setMaandTotaal1(maandTotaal1);
                inhoudingen.add(inhouding);
            }

        }
        maandTotaal1.setInhoudingen(inhoudingen);
    }

    private static boolean isBijpassingNetto(AardKodeExtensie loonCode) {
        return loonCode.getCode() == 5801 && loonCode.getExtensie() == 99;
    }

    private static Money bepaalBedragInhouding(LoonElement element) {
        Money bedrag = element.getPropertyMoney(RekenNettoKey.NETTO_KEY).negate();
        bedrag = bedrag.add(element.getPropertyMoney(RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_10_KEY));
        bedrag = bedrag.add(element.getPropertyMoney(RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_18_KEY));
        return bedrag;
    }

    protected boolean bepaalOpdrachtIsInOpzegOpEersteDagKwartaal(Opdracht opdracht, RekenHoofdArtikelKey key) {
        LocalDateInterval month = new Month(key.getBeginDatum());
        boolean heeftOpzeg = false;
        for (Opper opper : opdracht.getOpperSlices()) {
            LocalDateInterval interval = month.overlap(opper.getActualInterval());
            if (interval != null && isEersteDagKwartaal(interval.getStart()) && opper.getRszppo().getDienstverband() == Dienstverband.NEE_VERBREEK) {
                heeftOpzeg = true;
                break;
            }
        }
        return heeftOpzeg;
    }

    private static boolean isEersteDagKwartaal(LocalDate datum) {
        return datum.getDayOfMonth() == 1 && (datum.getMonthOfYear() - 1) % 3 == 0;
    }

    protected void nieuweResultatenBoeken(
            RekenHoofdArtikelKey rekenHoofdArtikelKey, ArtikelLoonElementManager manager, MaandTotaal1 maandTotaal1,
            RekenTijd rekenTijd, boolean belastbaarVrijwilligeBrandweer, boolean bv18Exists) {
        Collection<LoonElement> loonElementen =
                RekenElementBeheer.getRekenHoofdArtikelElementenKwartaal(rekenHoofdArtikelKey, manager, maandTotaal1.getAard());
        Map<AardKodeExtensie, RekenRszKey> rszOfTaoNatuur = onderzoekRszOfTaoNatuur(manager);
        for (LoonElement element : loonElementen) {
            vormMaandTotaalMoneyProperties(MT1_BRUTO_AND_RSZ_BASIS_KEYS, element, maandTotaal1);
            vormMaandTotaalMoneyProperties(MT1_RSZ_BIJDRAGE_KEYS, element, maandTotaal1);
            vormMaandTotaalMoneyProperties(MT1_PATRONALE_RSZ_BIJDRAGE_KEYS, element, maandTotaal1);
            vormMaandTotaalMoneyProperties(MT2_RSZ_BASIS_KEYS, element, maandTotaal1);
            vormMaandTotaalMoneyProperties(MT2_RSZ_BIJDRAGE_KEYS, element, maandTotaal1);
            vormMaandTotaalMoneyProperties(MT2_PATRONALE_RSZ_BIJDRAGE_KEYS, element, maandTotaal1);
            vormMaandTotaalMoneyProperties(MT2_VERMINDERING_BV_KEYS, element, maandTotaal1);
            vormMaandTotaalMoneyProperties(MT3_RSZ_BASIS_KEYS, element, maandTotaal1);
            vormMaandTotaalMoneyProperties(MT3_PATRONALE_RSZ_BIJDRAGE_KEYS, element, maandTotaal1);
            vormMaandTotaalMoneyProperties(OTHER_KEYS, element, maandTotaal1);

            vormMt1RszBijdrageEnBijdrageTaoEnWerkbonus(element, maandTotaal1, rszOfTaoNatuur);
            vormBelastbaar(element, maandTotaal1, rekenTijd.eindDatum, belastbaarVrijwilligeBrandweer);
            vormBelastbaarAchterstal(element, maandTotaal1);
            vormBedrijfsvoorheffing(element, maandTotaal1, rekenTijd.eindDatum, bv18Exists);
            vormBedrijfsvoorheffingAchterstal(element, maandTotaal1);
            vormNetto(element, maandTotaal1);
        }

    }

    private static void vormMaandTotaalMoneyProperties(Set<MoneyKey> keys, LoonElement element, MaandTotaal1 maandTotaal1) {
