    private static Map<AardKodeExtensie, RekenRszKey> onderzoekRszOfTaoNatuur(ArtikelLoonElementManager manager) {
        Set<RekenHoofdArtikelKey> keys = manager.getRekenHoofdArtikelKeys();
        Map<AardKodeExtensie, RekenRszKey> bijdrageNatuur = new HashMap<>();
        for (RekenHoofdArtikelKey key : keys) {
            onderzoekRszOfTaoNatuurRekenHoofdArtikelKey(manager, bijdrageNatuur, key);
        }
        return bijdrageNatuur;
    }

    private static void onderzoekRszOfTaoNatuurRekenHoofdArtikelKey(
            ArtikelLoonElementManager manager, Map<AardKodeExtensie, RekenRszKey> bijdrageNatuur, RekenHoofdArtikelKey key) {
        for (LoonElement element : manager.getRekenHoofdArtikelElementen(key)) {
            Money bijdrageRsz = element.getPropertyMoney(RekenRszKey.BIJDRAGE_RSZ_KEY);
            Money bijdrageTao = element.getPropertyMoney(RekenRszKey.BIJDRAGE_TAO_KEY);
            if (bijdrageRsz.signum() != 0 && bijdrageTao.signum() <= 0) {
                bijdrageNatuur.put(element.getAardKodeExtensie(), RekenRszKey.BIJDRAGE_RSZ_KEY);
            } else {
                if (bijdrageTao.signum() != 0) {
                    bijdrageNatuur.put(element.getAardKodeExtensie(), RekenRszKey.BIJDRAGE_TAO_KEY);
                }
            }
        }
    }

    private static void vormMt1RszBijdrageEnBijdrageTaoEnWerkbonus(
            LoonElement element, MaandTotaal1 maandTotaal1,
            Map<AardKodeExtensie, RekenRszKey> rszOfTaoNatuur) {
        Money bijdrageRsz = element.getPropertyMoney(RekenRszKey.BIJDRAGE_RSZ_KEY);
        Money bijdrageTao = element.getPropertyMoney(RekenRszKey.BIJDRAGE_TAO_KEY);
        Money werkbonus = element.getPropertyMoney(RekenRszKey.WERKBONUS_LAGE_LONEN_KEY);
        Money werkbonusB = element.getPropertyMoney(RekenRszKey.WERKBONUS_HEEL_LAGE_LONEN_KEY);
        Money werkbonusHerstructering = element.getPropertyMoney(RekenRszKey.VERMINDERING_HERSTRUCTERING_KEY);
        Money werkbonusGepensioneerd = element.getPropertyMoney(RekenRszKey.WERKBONUS_GEPENSIONEERD_KEY);
        RekenRszKey natuur = rszOfTaoNatuur.get(element.getAardKodeExtensie());
        boolean heeftWerkbonus = werkbonus.signum() != 0 || werkbonusB.signum() != 0 || werkbonusHerstructering.signum() != 0 || werkbonusGepensioneerd.signum() != 0;

        MaandTotaal2 maandTotaal2 = maandTotaal1.getMaandTotaal2();
        MaandTotaal3 maandTotaal3 = maandTotaal1.getMaandTotaal3();

        boolean werkbonusDone = false;
        if (bijdrageTao.signum() != 0 || (natuur == RekenRszKey.BIJDRAGE_TAO_KEY && heeftWerkbonus)) {
            Money bedrag = maandTotaal2.getInhoudingTijdelijkeArbeidsOngeschiktheid();
            bedrag = bedrag.add(bijdrageTao).subtract(werkbonus).subtract(werkbonusB).subtract(werkbonusGepensioneerd);
            maandTotaal2.setInhoudingTijdelijkeArbeidsOngeschiktheid(bedrag);

            Money verminderingLageLonenTao = maandTotaal2.getVerminderingLageLonenTao();
            maandTotaal2.setVerminderingLageLonenTao(verminderingLageLonenTao.add(werkbonus));

            Money verminderingGepensioneerdZorgsector = maandTotaal3.getVerminderingGepensioneerdenZorgsector();
            maandTotaal3.setVerminderingGepensioneerdenZorgsector(verminderingGepensioneerdZorgsector.add(werkbonusGepensioneerd));
            werkbonusDone = true;
        }
        boolean isBijdrageRsz = natuur == RekenRszKey.BIJDRAGE_RSZ_KEY && heeftWerkbonus;
        boolean isWerkbonusDone = !werkbonusDone && heeftWerkbonus;
        if (bijdrageRsz.signum() != 0 || isBijdrageRsz || isWerkbonusDone) {
            Money bedrag = maandTotaal1.getInhoudingRszZiv();
            bedrag = bedrag.add(bijdrageRsz);
            if (!werkbonusDone) {
                bedrag = bedrag.subtract(werkbonus).subtract(werkbonusB).subtract(werkbonusHerstructering).subtract(werkbonusGepensioneerd);
            }
            maandTotaal1.setInhoudingRszZiv(bedrag);

            if (!werkbonusDone) {
                Money verminderingLageLonen = maandTotaal2.getVerminderingLageLonen();
                maandTotaal2.setVerminderingLageLonen(verminderingLageLonen.add(werkbonus));

                Money verminderingHeelLageLonen = maandTotaal3.getVerminderingHeelLageLonen();
                maandTotaal3.setVerminderingHeelLageLonen(verminderingHeelLageLonen.add(werkbonusB));

                Money verminderingGepensioneerdZorgsector = maandTotaal3.getVerminderingGepensioneerdenZorgsector();
                maandTotaal3.setVerminderingGepensioneerdenZorgsector(verminderingGepensioneerdZorgsector.add(werkbonusGepensioneerd));
            }
        }

        Money verminderingHerstructering = maandTotaal2.getVerminderingHerstructering();
        verminderingHerstructering = verminderingHerstructering.add(werkbonusHerstructering);
        maandTotaal2.setVerminderingHerstructering(verminderingHerstructering);
    }

    private static void vormBelastbaar(
            LoonElement element, MaandTotaal1 maandTotaal1, LocalDate eindeMaand,
            boolean belastbaarVrijwilligeBrandweer) {
        LnedefRegBv regime = element.getRegimeBv();

        MoneyKey belastbaarKey;
        if (regime == LnedefRegBv.VD_BV_10_BZ___VB && belastbaarVrijwilligeBrandweer) {
            belastbaarKey = RekenBbKey.RUW_BELASTBAAR_KEY;
        } else {
            belastbaarKey = RekenBbKey.BELASTBAAR_KEY;
        }
        if (!REGIMES_BELASTBAAR_ACHTERSTAL_UNDIFFERENTIATED.contains(regime)) {
            belastbaarKey = new BelastbaarFiscaalJaarAchterstalKey(null, belastbaarKey, false);
        }

        if (regime == LnedefRegBv.VD_BV_10_OVERWERK) {
            boolean overwerkExceptioneel = eindeMaand.compareTo(new LocalDate(2012, 7, 1)) < 0;
            regime = overwerkExceptioneel ? LnedefRegBv.VD_BV_10_BZ___EXC : LnedefRegBv.VD_BV_10_BZ___GB;
        }

        BelastbaarKey bbKey = new BelastbaarKey(regime);
        Money bedrag = MaandTotaalUtil.getProperty(maandTotaal1, bbKey);
        bedrag = bedrag.add(element.getPropertyMoney(belastbaarKey));

        MaandTotaalUtil.setProperty(bedrag, maandTotaal1, bbKey);
    }

    private static void vormBelastbaarAchterstal(LoonElement element, MaandTotaal1 maandTotaal1) {
        LnedefRegBv regime = element.getRegimeBv();
        if (REGIMES_BELASTBAAR_ACHTERSTAL_UNDIFFERENTIATED.contains(regime)) {
            return;
        }
        if (regime == LnedefRegBv.VD_BV_10_UKAG_GB) {
            regime = LnedefRegBv.VD_BV_10_UKZI_GB;
        } else {
            if (REGIMES_ACHTERSTAL_GEWOON.contains(regime)) {
                regime = LnedefRegBv.VD_BV_10_BZ___GB;
            }
        }

        BelastbaarAchterstalKey bbKey = new BelastbaarAchterstalKey(regime);
        Money bedrag = MaandTotaalUtil.getProperty(maandTotaal1, bbKey);

        MoneyKey belastbaarHuidigFiscaalJaarKey = new BelastbaarFiscaalJaarAchterstalKey(maandTotaal1.getFiscaalJaar(), RekenBbKey.BELASTBAAR_KEY, true);
        bedrag = bedrag.add(element.getPropertyMoney(belastbaarHuidigFiscaalJaarKey));
        MoneyKey vrijstellingTotaalKey = new BelastbaarFiscaalJaarAchterstalKey(maandTotaal1.getFiscaalJaar(), RekenBbKey.VRIJSTELLING_BELASTBAAR_KEY, true);
        bedrag = bedrag.add(element.getPropertyMoney(vrijstellingTotaalKey));
        MaandTotaalUtil.setProperty(bedrag, maandTotaal1, bbKey);
    }

    private static void vormBedrijfsvoorheffing(LoonElement element, MaandTotaal1 maandTotaal1, LocalDate eindeMaand, boolean bv18Exists) {
        MaandTotaal2 maandTotaal2 = maandTotaal1.getMaandTotaal2();
        LnedefRegBv regime = element.getRegimeBv();
        RekenBvKey bvKey = BvTools.regimeToSingleBvKey(regime, eindeMaand);
        Money bedrag = element.getPropertyMoney(bvKey);
        boolean isBvGewoon = bvKey == RekenBvKey.BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY;
        boolean isBvTv = bvKey == RekenBvKey.BEDRIJFSVOORHEFFING_TOEVALLIGE_VERGOEDINGEN_KEY;
        boolean isBvExc = bvKey == RekenBvKey.BEDRIJFSVOORHEFFING_EXCEPTIONEEL_KEY;

        if (isBvGewoon) {
            Money vermindering = element.getPropertyMoney(RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY);
            Money verminderingB = element.getPropertyMoney(RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY);
            bedrag = bedrag.subtract(vermindering).subtract(verminderingB);
        }
        if (isBvGewoon) {
            zetBedrijfsVoorheffingGewoneBezoldiging(maandTotaal1, bv18Exists, maandTotaal2, regime, bedrag);
        } else if (isBvExc) {
            zetExceptioneleBedrijfsVoorheffing(maandTotaal1, maandTotaal2, regime, bedrag);
        } else {
            zetBedrijfsVoorheffingToevalligeVergoedingen(maandTotaal1, maandTotaal2, regime, bvKey, bedrag, isBvTv);
        }
    }

    private static void zetBedrijfsVoorheffingGewoneBezoldiging(
            MaandTotaal1 maandTotaal1, boolean bv18Exists, MaandTotaal2 maandTotaal2, LnedefRegBv regime, Money bedrag) {
        if ((regime == LnedefRegBv.VD_BV_10_UKZI_GB || regime == LnedefRegBv.VD_BV_10_UKAG_GB) && (
                maandTotaal1.getBeginDatum().getYear() >= BvTools.STARTJAAR_FICHE_281_18 || bv18Exists)) {
            Money bedrijfsvoorheffingZiv = bedrag.add(maandTotaal1.getBedrijfsvoorheffingZiv());
            maandTotaal1.setBedrijfsvoorheffingZiv(bedrijfsvoorheffingZiv);
        } else if (regime == LnedefRegBv.VD_BV_11_PENS_GB) {
            Money bedrijfsvoorheffingPensioen = bedrag.add(maandTotaal2.getBedrijfsvoorheffingPensioen());
            maandTotaal2.setBedrijfsvoorheffingPensioen(bedrijfsvoorheffingPensioen);
        } else if (regime == LnedefRegBv.VD_BV_20_VEREFFENAAR) {
            Money bedrijfsvoorheffingVereffenaar = bedrag.add(maandTotaal2.getBedrijfsvoorheffingVereffenaar());
            maandTotaal2.setBedrijfsvoorheffingVereffenaar(bedrijfsvoorheffingVereffenaar);
        } else if (regime == LnedefRegBv.VD_BV_17_BRUG_PENS) {
            Money bedrijfsvoorheffingBrugPensioen = bedrag.add(maandTotaal2.getBedrijfsvoorheffingBrugPensioen());
            maandTotaal2.setBedrijfsvoorheffingBrugPensioen(bedrijfsvoorheffingBrugPensioen);
        } else {
            Money bedrijfsvoorheffingGewoneBezoldigingen = bedrag.add(maandTotaal1.getBedrijfsvoorheffingGewoneBezoldigingen());
            maandTotaal1.setBedrijfsvoorheffingGewoneBezoldigingen(bedrijfsvoorheffingGewoneBezoldigingen);
        }
    }

    private static void zetExceptioneleBedrijfsVoorheffing(MaandTotaal1 maandTotaal1, MaandTotaal2 maandTotaal2, LnedefRegBv regime, Money bedrag) {
