    private static void zetBedrijfsVoorheffingToevalligeVergoedingen(
            MaandTotaal1 maandTotaal1, MaandTotaal2 maandTotaal2, LnedefRegBv regime, RekenBvKey bvKey, Money bedrag, boolean isBvTv) {
        if (isBvTv && regime == LnedefRegBv.VD_BV_10_BZ___TV) {
