    private static void vormNetto(LoonElement element, MaandTotaal1 maandTotaal1) {
        if (!element.getAardKodeExtensie().getAard().equals(AardKodeExt.I_KODE_EXT.getCode())) {
            Money netto = maandTotaal1.getNetto();
            netto = netto.add(element.getPropertyMoney(RekenNettoKey.NETTO_KEY));
            maandTotaal1.setNetto(netto);
        } else {
            Money netto = maandTotaal1.getNetto();
            netto = netto.add(element.getPropertyMoney(RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_10_KEY));
            netto = netto.add(element.getPropertyMoney(RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_FICHE_18_KEY));
            maandTotaal1.setNetto(netto);

            Money wgBijdrageMtc = maandTotaal1.getWerkgeversBijdrageMaaltijdCheques();
            wgBijdrageMtc = wgBijdrageMtc.add(element.getPropertyMoney(RekenNettoKey.BIJDRAGE_WG_MTC));
            maandTotaal1.setWerkgeversBijdrageMaaltijdCheques(wgBijdrageMtc);
        }

        Money teBetalen = maandTotaal1.getTeBetalen();
        teBetalen = teBetalen.add(element.getPropertyMoney(RekenNettoKey.NETTO_KEY));
        maandTotaal1.setTeBetalen(teBetalen);
    }

