    protected void fixTeBetalenTeVorderen(MaandTotaal1 maandTotaal1) {
        Money bedrag = maandTotaal1.getTeBetalen().subtract(maandTotaal1.getTeVorderen());
        if (bedrag.signum() < 0) {
            maandTotaal1.setTeBetalen(Money.ZERO);
            maandTotaal1.setTeVorderen(bedrag.negate());
        } else {
            maandTotaal1.setTeVorderen(Money.ZERO);
            maandTotaal1.setTeBetalen(bedrag);
        }
    }

    protected Inhouding maakInhouding(RekenElementenKey loonCode, Money bedrag) {
        Inhouding inhouding = new InhoudingPO();
        inhouding.setTijdperk(loonCode.getTijdperk());
        inhouding.setCode(loonCode.getCode());
        inhouding.setExtensie(loonCode.getExtensie());
        inhouding.setBedrag(bedrag);
        return inhouding;
    }

    protected ListMultimap<Integer, MaandTotaal1> mapOpdrachtNrToBestaanden(List<MaandTotaal1> bestaanden) {
        ListMultimap<Integer, MaandTotaal1> map = ArrayListMultimap.create();
        for (MaandTotaal1 maandTotaal : bestaanden) {
            map.put(maandTotaal.getOpdrachtNummer(), maandTotaal);
        }
        return map;
    }

    protected ListMultimap<RekenElementenBoekingKey, RekenElement> mapOpdrachtNrLooncodeToRekenElementen(List<MaandTotaal1> bestaanden) {
        ListMultimap<RekenElementenBoekingKey, RekenElement> map = ArrayListMultimap.create();
        for (MaandTotaal1 maandTotaal : bestaanden) {
            for (RekenElement element : maandTotaal.getRekenElementen()) {
                RekenElementenBoekingKey key =
                        new RekenElementenBoekingKey(maandTotaal.getOpdrachtNummer(), element.getTijdperk(), element.getAard(), element.getCode(),
                                element.getExtensie(), element.getVakantieReferentiejaar(), element.getBeginDatum(), element.getEindDatum(),
                                AardRekenelement.getByCode(element.getTypeBoeking()));
                map.put(key, element);
            }
        }
        return map;
    }

    protected ListMultimap<RekenElementenKey, Inhouding> mapOpdrachtNrLooncodeToInhoudingen(List<MaandTotaal1> bestaanden) {
        ListMultimap<RekenElementenKey, Inhouding> map = ArrayListMultimap.create();
        for (MaandTotaal1 maandTotaal : bestaanden) {
            LocalDate beginDatum = maandTotaal.getBeginDatum().dayOfMonth().withMinimumValue();
            LocalDate eindDatum = beginDatum.dayOfMonth().withMaximumValue();
            for (Inhouding element : maandTotaal.getInhoudingen()) {
                RekenElementenKey key =
                        new RekenElementenKey(maandTotaal.getOpdrachtNummer(), element.getTijdperk(), AardKodeExt.I_KODE_EXT.getCode(), element.getCode(),
                                element.getExtensie(), 0, beginDatum, eindDatum);
                map.put(key, element);
            }
        }
        return map;
    }

    protected Set<RekenHoofdArtikelKey> getRekenHoofdArtikelKeyHuidigeOpdracht(
            ArtikelLoonElementManager manager, Opdracht opdracht, RekenTijd rekenTijd, boolean afwijkendeVerwerkingPerMaand) {
        return manager.getRekenHoofdArtikelKeys().stream()
                .filter(key -> key.getOpdrachtId().equals(opdracht.getId()))
                .map(key -> voegRekenHoofdArtikelsToe(opdracht, rekenTijd, afwijkendeVerwerkingPerMaand, key))
                .collect(Collectors.toCollection(TreeSet::new));
    }

    private static RekenHoofdArtikelKey voegRekenHoofdArtikelsToe(
            Opdracht opdracht, RekenTijd rekenTijd, boolean afwijkendeVrwPerMaand, RekenHoofdArtikelKey key) {
        if (isOpdrachtKwartaalMaandTotalen(opdracht, rekenTijd, afwijkendeVrwPerMaand)) {
            Quarter kwartaal = new Quarter(key.getBeginDatum());
            return new RekenHoofdArtikelKey(key, kwartaal.getStart());
        } else {
            return key;
        }
    }

    private static boolean isOpdrachtKwartaalMaandTotalen(Opdracht opdracht, RekenTijd rekenTijd, boolean hvzAfwijkendeVerwerkingPerMaand) {
        boolean opdrachtMetKwartaalMaandtotalen = RekenTools.isOpdrachtMetKwartaalMaandtotalen(opdracht.getHoedanigheid());
        return opdrachtMetKwartaalMaandtotalen && !rekenTijd.isApo && !hvzAfwijkendeVerwerkingPerMaand;
    }

    protected ListMultimap<RekenHoofdArtikelKey, MaandTotaal1> mapRekenHoofdKeyToMaandTotalen(
            Opdracht opdracht,
            List<MaandTotaal1> opdrachtBestaanden) {
        ListMultimap<RekenHoofdArtikelKey, MaandTotaal1> map = ArrayListMultimap.create();
        for (MaandTotaal1 maandTotaal : opdrachtBestaanden) {
            map.put(new RekenHoofdArtikelKey(opdracht, maandTotaal), maandTotaal);
        }
        return map;
    }

    protected List<MaandTotaal1> cleanNulResultaten(List<MaandTotaal1> maandTotalenPersoon) {
        ListMultimap<Integer, MaandTotaal1> opdrachtNrToMaandTotaal = Multimaps.index(maandTotalenPersoon, MaandTotaal1::getOpdrachtNummer);
        List<MaandTotaal1> cleaned = new ArrayList<>();
        for (Integer opdrachtnr : opdrachtNrToMaandTotaal.keySet()) {
            List<MaandTotaal1> maandTotalen = opdrachtNrToMaandTotaal.get(opdrachtnr);
            boolean nulAanwezig = false;
            boolean nietNulAanwezig = false;
            for (MaandTotaal1 maandTotaal1 : maandTotalen) {
                boolean zeroMaandtotaal = maandTotaal1.isZeroMaandtotaal();
                nietNulAanwezig = nietNulAanwezig || !zeroMaandtotaal;
                nulAanwezig = nulAanwezig || zeroMaandtotaal;
            }
            if (nietNulAanwezig) {
                maandTotalen.forEach(maandTotaal1 -> voegMaandTotaalToeWaarBedragenMaandtotaalnietNulZijnOfBrutoEnSocialeInhoudingenAanwezigZijn(cleaned, maandTotaal1));
            } else if (nulAanwezig) {
                maandTotalen.forEach(maandTotaal1 -> voegMaandTotalenToeWaarRnummerGelijkIsAanSnummerOfBrutoEnSocialeInhoudingenAanwezigZijn(cleaned, maandTotaal1));
            }

        }
        return cleaned;
    }

    private static void voegMaandTotalenToeWaarRnummerGelijkIsAanSnummerOfBrutoEnSocialeInhoudingenAanwezigZijn(List<MaandTotaal1> cleaned, MaandTotaal1 maandTotaal1) {
        Set<RekenElement> elementen = bepaalRekenElementWaarBrutoOfSocialeInhoudingenAanwezigZijn(maandTotaal1);
        if (maandTotaal1.getRnummer().equals(maandTotaal1.getSnummer()) || !elementen.isEmpty()) {
            cleaned.add(maandTotaal1);
        }
    }

    private static void voegMaandTotaalToeWaarBedragenMaandtotaalnietNulZijnOfBrutoEnSocialeInhoudingenAanwezigZijn(
            List<MaandTotaal1> cleaned, MaandTotaal1 maandTotaal1) {

        Set<RekenElement> elementen = bepaalRekenElementWaarBrutoOfSocialeInhoudingenAanwezigZijn(maandTotaal1);
        if (!elementen.isEmpty() || !maandTotaal1.isZeroMaandtotaal()) {
            maandTotaal1.setRekenElementen(elementen);
            cleaned.add(maandTotaal1);
        }
    }

    private static Set<RekenElement> bepaalRekenElementWaarBrutoOfSocialeInhoudingenAanwezigZijn(MaandTotaal1 maandTotaal1) {
        return maandTotaal1.getRekenElementen().stream()
                .filter(x -> brutoBedragisNietNull(x) || socialeInhoudingenZijnNietNull(x))
                .collect(Collectors.toSet());
    }

    private static boolean socialeInhoudingenZijnNietNull(RekenElement x) {
        return x.getBasisSocialeInhoudingen().signum() != 0;
    }

    private static boolean brutoBedragisNietNull(RekenElement rekenElement) {
        return rekenElement.getBruto().signum() != 0;
    }
